- "celestial vessels" refers to aircraft;
- "journey of training" refers to flight sessions type 'training';
- "makers" refer to the manufacturers;
- "journey beyond the year 2015" refers to model year greater than 2015;
- "birth year" refers to the model year;
- "refitting hands" refers to modification date.

sql:
SELECT DISTINCT session_id
FROM fw_control_yaw
WHERE fw_control_yaw > 0.8;

SELECT aircraft.aircraft_name, aircraft.configuration, sensors.sensor_name, sensors.sensor_type
FROM aircraft
INNER JOIN sensors ON aircraft.aircraft_id = sensors.aircraft_id;

SELECT session_id
FROM yaw_reset_integral
WHERE yaw_reset_integral > 0.7;
